blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie nauczysz się odróżniać <strong>rzeczowniki policzalne</strong> od <strong>niepoliczalnych</strong> i poprawnie używać ich z przedimkami oraz określeniami ilości.",
    "rules": [
        {
            "label": "Countable",
            "color": "emerald",
            "text": "<strong>policzalne</strong> — można je policzyć:",
            "example": "one apple, two apples, three books"
        },
        {
            "label": "Uncountable",
            "color": "amber",
            "text": "<strong>niepoliczalne</strong> — nie liczymy ich w prosty sposób:",
            "example": "water, information, advice, music"
        },
        {
            "label": "Articles",
            "color": "blue",
            "text": "<strong>a / an</strong> używamy tylko z rzeczownikami policzalnymi w liczbie pojedynczej:",
            "example": "a book ✓ / a water ✗"
        }
    ]
}

{
    "title": "1. Czym są rzeczowniki policzalne i niepoliczalne?",
    "intro": "Rzeczowniki dzielimy na dwie główne grupy:",
    "items": [
        {
            "label": "Countable",
            "title": "Policzalne",
            "subtitle": "Można je policzyć i mają liczbę pojedynczą oraz mnogą: apple → apples"
        },
        {
            "label": "Uncountable",
            "title": "Niepoliczalne",
            "subtitle": "Nie liczymy ich pojedynczo i zwykle nie mają liczby mnogiej: water, music"
        },
        {
            "label": "Both",
            "title": "Obie formy",
            "subtitle": "Niektóre rzeczowniki mogą działać na dwa sposoby, np. chicken = mięso / kura"
        }
    ]
}

{
    "title": "2. Countable Nouns — rzeczowniki policzalne",
    "sections": [
        {
            "label": "Jak je rozpoznać",
            "color": "emerald",
            "description": "<strong>Rzeczowniki policzalne</strong> można liczyć. Mają liczbę pojedynczą i mnogą.",
            "examples": [
                {
                    "en": "one book, two books, three books",
                    "ua": "jedna książka, dwie książki, trzy książki"
                },
                {
                    "en": "a cat, some cats, many cats",
                    "ua": "kot, kilka kotów, wiele kotów"
                },
                {
                    "en": "an idea, several ideas",
                    "ua": "pomysł, kilka pomysłów"
                }
            ]
        },
        {
            "label": "Z a / an",
            "color": "sky",
            "description": "Rzeczownik policzalny w liczbie pojedynczej zwykle potrzebuje <strong>a / an</strong> albo innego określnika.",
            "examples": [
                {
                    "en": "I need a pen.",
                    "ua": "Potrzebuję długopisu."
                },
                {
                    "en": "She is an engineer.",
                    "ua": "Ona jest inżynierką."
                },
                {
                    "en": "Give me the book.",
                    "ua": "Daj mi tę książkę."
                }
            ],
            "note": "❌ Nie mówimy <em>I need pen</em>, jeśli chodzi o jeden konkretny policzalny przedmiot."
        },
        {
            "label": "Typowe przykłady",
            "color": "amber",
            "description": "Do rzeczowników policzalnych należą często przedmioty, osoby i pojedyncze idee.",
            "examples": [
                {
                    "en": "book, pen, table, chair",
                    "ua": "book, pen, table, chair"
                },
                {
                    "en": "apple, banana, egg, sandwich",
                    "ua": "apple, banana, egg, sandwich"
                },
                {
                    "en": "person, friend, student, teacher",
                    "ua": "person, friend, student, teacher"
                },
                {
                    "en": "idea, problem, question, answer",
                    "ua": "idea, problem, question, answer"
                }
            ]
        }
    ]
}

{
    "title": "3. Uncountable Nouns — rzeczowniki niepoliczalne",
    "sections": [
        {
            "label": "Jak je rozpoznać",
            "color": "amber",
            "description": "<strong>Rzeczowników niepoliczalnych</strong> nie liczymy zwykle sztuka po sztuce. Najczęściej nie mają liczby mnogiej i łączą się z czasownikiem w liczbie pojedynczej.",
            "examples": [
                {
                    "en": "Water is important.",
                    "ua": "Woda jest ważna."
                },
                {
                    "en": "Information is useful.",
                    "ua": "Informacja jest przydatna."
                },
                {
                    "en": "Music makes me happy.",
                    "ua": "Muzyka sprawia mi radość."
                }
            ]
        },
        {
            "label": "Bez a / an",
            "color": "rose",
            "description": "Z rzeczownikami niepoliczalnymi <strong>nie używamy</strong> przedimków <strong>a / an</strong>.",
            "examples": [
                {
                    "en": "✓ I need water.",
                    "ua": "Potrzebuję wody."
                },
                {
                    "en": "✗ I need a water.",
                    "ua": "to zdanie jest niepoprawne"
                },
                {
                    "en": "✓ She gave me advice.",
                    "ua": "Dała mi radę."
                },
                {
                    "en": "✗ She gave me an advice.",
                    "ua": "to zdanie jest niepoprawne"
                }
            ]
        },
        {
            "label": "Typowe grupy",
            "color": "sky",
            "description": "Do niepoliczalnych często należą płyny, materiały, pojęcia abstrakcyjne i „masy” jedzenia.",
            "examples": [
                {
                    "en": "Liquids: water, milk, coffee, tea, juice",
                    "ua": "płyny: water, milk, coffee, tea, juice"
                },
                {
                    "en": "Materials: wood, plastic, glass, paper",
                    "ua": "materiały: wood, plastic, glass, paper"
                },
                {
                    "en": "Abstract: information, advice, news, knowledge",
                    "ua": "pojęcia abstrakcyjne: information, advice, news, knowledge"
                },
                {
                    "en": "Food masses: rice, bread, sugar, salt, meat",
                    "ua": "produkty masowe: rice, bread, sugar, salt, meat"
                }
            ]
        }
    ]
}

{
    "title": "4. Jak mierzyć rzeczowniki niepoliczalne",
    "sections": [
        {
            "label": "Jednostki miary",
            "color": "emerald",
            "description": "Żeby „policzyć” rzeczownik niepoliczalny, używamy <strong>jednostki miary lub pojemnika</strong>.",
            "examples": [
                {
                    "en": "a glass of water",
                    "ua": "szklanka wody"
                },
                {
                    "en": "a cup of coffee",
                    "ua": "filiżanka kawy"
                },
                {
                    "en": "a bottle of milk",
                    "ua": "butelka mleka"
                },
                {
                    "en": "a piece of advice",
                    "ua": "jedna rada"
                }
            ]
        },
        {
            "label": "Typowe konstrukcje",
            "color": "sky",
            "description": "Różne rzeczowniki łączą się z różnymi „opakowaniami” lub porcjami.",
            "examples": [
                {
                    "en": "a piece of: cake, paper, news, furniture",
                    "ua": "a piece of: cake, paper, news, furniture"
                },
                {
                    "en": "a slice of: bread, pizza, cheese",
                    "ua": "a slice of: bread, pizza, cheese"
                },
                {
                    "en": "a loaf of: bread",
                    "ua": "a loaf of bread"
                },
                {
                    "en": "a bar of: chocolate, soap",
                    "ua": "a bar of: chocolate, soap"
                }
            ]
        },
        {
            "label": "Some / a bit of / a little",
            "color": "amber",
            "description": "Do nieokreślonej ilości często używamy <strong>some</strong>, <strong>a bit of</strong> albo <strong>a little</strong>.",
            "examples": [
                {
                    "en": "some water, some information",
                    "ua": "some water, some information"
                },
                {
                    "en": "a bit of luck, a bit of help",
                    "ua": "a bit of luck, a bit of help"
                },
                {
                    "en": "a little sugar, a little time",
                    "ua": "a little sugar, a little time"
                }
            ]
        }
    ]
}

{
    "title": "5. Quantifiers — określenia ilości",
    "sections": [
        {
            "label": "Tylko policzalne",
            "color": "emerald",
            "description": "Te określenia używamy <strong>tylko z rzeczownikami policzalnymi</strong>.",
            "examples": [
                {
                    "en": "many books, many friends",
                    "ua": "many books, many friends"
                },
                {
                    "en": "a few questions",
                    "ua": "a few questions"
                },
                {
                    "en": "few people",
                    "ua": "few people"
                },
                {
                    "en": "several ideas",
                    "ua": "several ideas"
                }
            ]
        },
        {
            "label": "Tylko niepoliczalne",
            "color": "amber",
            "description": "Te określenia łączą się <strong>tylko z rzeczownikami niepoliczalnymi</strong>.",
            "examples": [
                {
                    "en": "much time, much money",
                    "ua": "much time, much money"
                },
                {
                    "en": "a little water",
                    "ua": "a little water"
                },
                {
                    "en": "little hope",
                    "ua": "little hope"
                }
            ]
        },
        {
            "label": "Dla obu typów",
            "color": "sky",
            "description": "Niektóre wyrażenia ilości są uniwersalne i pasują do obu grup.",
            "examples": [
                {
                    "en": "some books / some water",
                    "ua": "some books / some water"
                },
                {
                    "en": "any questions / any information",
                    "ua": "any questions / any information"
                },
                {
                    "en": "a lot of friends / a lot of time",
                    "ua": "a lot of friends / a lot of time"
                },
                {
                    "en": "lots of people / lots of money",
                    "ua": "lots of people / lots of money"
                }
            ]
        }
    ]
}

{
    "title": "6. Tabela porównawcza",
    "intro": "Najważniejsze różnice między rzeczownikami policzalnymi i niepoliczalnymi:",
    "rows": [
        {
            "en": "Plural form",
            "ua": "liczba mnoga",
            "note": "Countable: books ✓ / Uncountable: waters ✗"
        },
        {
            "en": "A / An",
            "ua": "przedimek a / an",
            "note": "Countable: a book ✓ / Uncountable: a water ✗"
        },
        {
            "en": "Numbers",
            "ua": "liczebniki",
            "note": "Countable: two books ✓ / Uncountable: two waters ✗"
        },
        {
            "en": "Many / Much",
            "ua": "dużo",
            "note": "Countable: many ✓ / Uncountable: much ✓"
        },
        {
            "en": "Few / Little",
            "ua": "mało",
            "note": "Countable: few ✓ / Uncountable: little ✓"
        }
    ],
    "warning": "📌 <strong>A lot of</strong>, <strong>some</strong> i <strong>any</strong> pasują do obu typów rzeczowników."
}

{
    "title": "7. Rzeczowniki o podwójnym znaczeniu",
    "sections": [
        {
            "label": "To samo słowo, inne znaczenie",
            "color": "purple",
            "description": "Niektóre rzeczowniki mogą być <strong>policzalne albo niepoliczalne</strong>, ale znaczenie się wtedy zmienia.",
            "examples": [
                {
                    "en": "chicken (uncountable) = meat",
                    "ua": "chicken jako mięso"
                },
                {
                    "en": "a chicken (countable) = bird",
                    "ua": "a chicken jako kura"
                },
                {
                    "en": "coffee (uncountable) = drink",
                    "ua": "coffee jako napój"
                },
                {
                    "en": "a coffee (countable) = a cup",
                    "ua": "a coffee jako filiżanka kawy"
                }
            ]
        },
        {
            "label": "Więcej przykładów",
            "color": "sky",
            "description": "Podobna różnica dotyczy także innych słów.",
            "examples": [
                {
                    "en": "glass (uncountable) = material",
                    "ua": "glass jako materiał"
                },
                {
                    "en": "a glass (countable) = container",
                    "ua": "a glass jako szklanka"
                },
                {
                    "en": "paper (uncountable) = material",
                    "ua": "paper jako papier"
                },
                {
                    "en": "a paper (countable) = document/newspaper",
                    "ua": "a paper jako dokument lub gazeta"
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dodawanie liczby mnogiej do rzeczownika niepoliczalnego.",
            "wrong": "I need some informations.",
            "right": "✅ <span class=\"font-mono\">I need some information.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie a / an z rzeczownikiem niepoliczalnym.",
            "wrong": "Can I have a water?",
            "right": "✅ <span class=\"font-mono\">Can I have some water?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie much z rzeczownikiem policzalnym.",
            "wrong": "There are much books here.",
            "right": "✅ <span class=\"font-mono\">There are many books here.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie many z rzeczownikiem niepoliczalnym.",
            "wrong": "I have many money.",
            "right": "✅ <span class=\"font-mono\">I have much money. / I have a lot of money.</span>"
        }
    ]
}

{
    "title": "10. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Określ typ rzeczownika",
    "select_intro": "Zdecyduj, czy rzeczownik jest policzalny (C), czy niepoliczalny (U).",
    "selects": [
        {
            "label": "water (C / U)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "book (C / U)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "information (C / U)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "apple (C / U)",
            "prompt": "Jaki to typ?"
        }
    ],
    "options": [
        "Countable",
        "Uncountable"
    ],
    "input_title": "Ćwiczenie 2. Wstaw many albo much",
    "input_intro": "Uzupełnij zdania odpowiednim słowem.",
    "inputs": [
        {
            "before": "How ___ books do you have?",
            "after": "→"
        },
        {
            "before": "I don't have ___ time.",
            "after": "→"
        },
        {
            "before": "There are ___ people here.",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I need an advice.",
            "example_target": "I need some advice. / I need a piece of advice."
        },
        {
            "original": "1. She gave me many informations.",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "2. Can I have a milk?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Countable / Uncountable Nouns",
            "current": true
        },
        {
            "label": "Articles",
            "current": false
        },
        {
            "label": "Zero Article",
            "current": false
        },
        {
            "label": "Quantifiers",
            "current": false
        }
    ]
}
